class Solution:
    def minimumRecolors(self, blocks, k):
        n = len(blocks)
        best = k
        for i in range(n - k + 1):
            whites = sum(1 for c in blocks[i:i + k] if c == 'W')
            if whites < best:
                best = whites
        return best

