class Solution:
    def minimumRecolors(self, blocks, k):
        whites = sum(1 for c in blocks[:k] if c == 'W')
        best = whites
        for i in range(k, len(blocks)):
            whites += (blocks[i] == 'W') - (blocks[i - k] == 'W')
            if whites < best:
                best = whites
        return best

