var minimumRecolors = function(blocks, k) {
    let whites = 0;
    for (let i = 0; i < k; i++) if (blocks[i] === 'W') whites++;
    let best = whites;
    for (let i = k; i < blocks.length; i++) {
        if (blocks[i] === 'W') whites++;
        if (blocks[i - k] === 'W') whites--;
        if (whites < best) best = whites;
    }
    return best;
};
